const t=JSON.parse('{"key":"v-7d9fb4ce","path":"/posts/%E6%B5%8B%E7%BB%98/%E6%BF%80%E5%85%89%E9%9B%B7%E8%BE%BE%EF%BC%88LiDAR%EF%BC%89.html","title":"激光雷达（LiDAR）","lang":"en-US","frontmatter":{"description":"激光雷达（LiDAR） 激光雷达 (LiDAR) 技术文档 1. 概述 激光雷达 (Light Detection and Ranging, LiDAR) 是一种主动遥感技术，通过发射激光脉冲并接收其反射信号来探测目标物体的距离、方位和特征信息。LiDAR 系统通常由激光发射器、接收器、扫描系统和数据处理单元组成。 2. 工作原理 LiDAR 系统的工作原理可以概括为以下步骤： 激光发射: 激光发射器发射出短脉冲激光束。 光束扫描: 扫描系统控制激光束的发射方向，使其按照预设的扫描模式（例如，旋转、线性扫描等）对目标区域进行扫描。 目标反射: 激光束遇到目标物体后发生反射，部分反射光返回 LiDAR 系统。 信号接收: 接收器接收反射回来的激光信号，并将其转换为电信号。 时间测量: 系统测量激光脉冲从发射到接收的时间差，即飞行时间 (Time of Flight, ToF)。 距离计算: 根据光速和飞行时间，计算出目标物体与 LiDAR 系统之间的距离。 数据处理: 系统将距离信息与扫描角度、位置信息等结合，生成目标物体的三维点云数据。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/posts/%E6%B5%8B%E7%BB%98/%E6%BF%80%E5%85%89%E9%9B%B7%E8%BE%BE%EF%BC%88LiDAR%EF%BC%89.html"}],["meta",{"property":"og:site_name","content":"入川为王"}],["meta",{"property":"og:title","content":"激光雷达（LiDAR）"}],["meta",{"property":"og:description","content":"激光雷达（LiDAR） 激光雷达 (LiDAR) 技术文档 1. 概述 激光雷达 (Light Detection and Ranging, LiDAR) 是一种主动遥感技术，通过发射激光脉冲并接收其反射信号来探测目标物体的距离、方位和特征信息。LiDAR 系统通常由激光发射器、接收器、扫描系统和数据处理单元组成。 2. 工作原理 LiDAR 系统的工作原理可以概括为以下步骤： 激光发射: 激光发射器发射出短脉冲激光束。 光束扫描: 扫描系统控制激光束的发射方向，使其按照预设的扫描模式（例如，旋转、线性扫描等）对目标区域进行扫描。 目标反射: 激光束遇到目标物体后发生反射，部分反射光返回 LiDAR 系统。 信号接收: 接收器接收反射回来的激光信号，并将其转换为电信号。 时间测量: 系统测量激光脉冲从发射到接收的时间差，即飞行时间 (Time of Flight, ToF)。 距离计算: 根据光速和飞行时间，计算出目标物体与 LiDAR 系统之间的距离。 数据处理: 系统将距离信息与扫描角度、位置信息等结合，生成目标物体的三维点云数据。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"en-US"}],["meta",{"property":"og:updated_time","content":"2025-08-16T04:37:55.000Z"}],["meta",{"property":"article:author","content":"入川为王"}],["meta",{"property":"article:modified_time","content":"2025-08-16T04:37:55.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"激光雷达（LiDAR）\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2025-08-16T04:37:55.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"入川为王\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"激光雷达 (LiDAR) 技术文档","slug":"激光雷达-lidar-技术文档","link":"#激光雷达-lidar-技术文档","children":[]}],"git":{"createdTime":1755319075000,"updatedTime":1755319075000,"contributors":[{"name":"TikTrack Developer","email":"user@example.com","commits":1}]},"readingTime":{"minutes":3.59,"words":1077},"filePathRelative":"posts/测绘/激光雷达（LiDAR）.md","localizedDate":"August 16, 2025","excerpt":"<h1> 激光雷达（LiDAR）</h1>\\n<h2> 激光雷达 (LiDAR) 技术文档</h2>\\n<p><strong>1. 概述</strong></p>\\n<p>激光雷达 (Light Detection and Ranging, LiDAR) 是一种主动遥感技术，通过发射激光脉冲并接收其反射信号来探测目标物体的距离、方位和特征信息。LiDAR 系统通常由激光发射器、接收器、扫描系统和数据处理单元组成。</p>\\n<p><strong>2. 工作原理</strong></p>\\n<p>LiDAR 系统的工作原理可以概括为以下步骤：</p>\\n<ol>\\n<li><strong>激光发射:</strong>  激光发射器发射出短脉冲激光束。</li>\\n<li><strong>光束扫描:</strong>  扫描系统控制激光束的发射方向，使其按照预设的扫描模式（例如，旋转、线性扫描等）对目标区域进行扫描。</li>\\n<li><strong>目标反射:</strong>  激光束遇到目标物体后发生反射，部分反射光返回 LiDAR 系统。</li>\\n<li><strong>信号接收:</strong>  接收器接收反射回来的激光信号，并将其转换为电信号。</li>\\n<li><strong>时间测量:</strong>  系统测量激光脉冲从发射到接收的时间差，即飞行时间 (Time of Flight, ToF)。</li>\\n<li><strong>距离计算:</strong>  根据光速和飞行时间，计算出目标物体与 LiDAR 系统之间的距离。</li>\\n<li><strong>数据处理:</strong>  系统将距离信息与扫描角度、位置信息等结合，生成目标物体的三维点云数据。</li>\\n</ol>","autoDesc":true}');export{t as data};
